    addQuickSupplierFromProductForm(event) {
        event.preventDefault();
        const form = event.target;
        const name = (form.querySelector('input[name="name"]').value || '').trim();
        const phone = (form.querySelector('input[name="phone"]').value || '').trim();
        if (!name) {
            this.showNotification('Vui lòng nhập tên nhà cung cấp.', 'warning');
            return;
        }
        const newId = 'NCC' + String(this.demoData.suppliers.length + 1).padStart(3, '0');
        const newSupplier = { id: newId, name: name, type: 'ca-nhan', phone: phone || '', email: '', address: '', supplierCode: '', taxCode: '', legalRepresentative: '', contactPosition: '' };
        this.demoData.suppliers.push(newSupplier);
        this.saveToLocalStorage();
        const select = document.getElementById('add-product-supplier-select');
        if (select) {
            const opt = document.createElement('option');
            opt.value = newId;
            opt.textContent = name;
            opt.selected = true;
            select.appendChild(opt);
        }
        document.getElementById('quick-add-supplier-modal').remove();
        this.showNotification(`Đã thêm nhà cung cấp "${name}" và chọn trong form.`, 'success');
    }
    
    addProductFromForm(form, createAnother) {
        this.clearFieldErrors(form);
        if (!this.validateFormProduct(form)) return;
        const formData = new FormData(form);
        // Xử lý IMEI (mỗi máy 1 IMEI, có thể dán nhiều IMEI cách nhau bởi , ; hoặc xuống dòng)
        const imeiRaw = (formData.get('imei') || '').toString().trim();
        const imeis = imeiRaw ? imeiRaw.split(/[\n,;]+/).map(v => v.trim()).filter(v => v.length > 0) : [];
        const stockModeImei = !!formData.get('stockModeImei');
        const hasImei = stockModeImei && imeis.length > 0;
        
        const nextIndex = this.demoData.products.length;
        const fallbackId = 'SP' + String(nextIndex + 1).padStart(3, '0');
        const draftProduct = {
            id: fallbackId,
            name: formData.get('name'),
            category: formData.get('category'),
        };
        const autoBarcode = this.generateAutoBarcode(draftProduct, nextIndex);
        const newProduct = {
            id: 'SP' + String(this.demoData.products.length + 1).padStart(3, '0'),
            name: formData.get('name'),
            category: formData.get('category'),
            barcode: autoBarcode,
            printBarcode: true,
            importPrice: this.parsePrice(formData.get('importPrice')),
            price: this.parsePrice(formData.get('price')),
            stock: hasImei ? imeis.length : parseInt(formData.get('stock') || '0'),
            minStock: hasImei ? 0 : (() => { const m = parseInt(formData.get('minStock'), 10); return isNaN(m) ? 1 : Math.max(0, m); })(),
            supplier: formData.get('supplier'),
            hasImei,
            imeis: hasImei ? imeis : []
        };
        
        this.demoData.products.push(newProduct);
        this.saveToLocalStorage();
        this.showNotification(`Đã thêm sản phẩm ${newProduct.name}`, 'success');
        if (createAnother) {
            form.querySelector('input[name="name"]').value = '';
            const imeiInput = form.querySelector('input[name="imei"]');
            if (imeiInput) imeiInput.value = '';
            const importPriceInput = form.querySelector('input[name="importPrice"]');
            if (importPriceInput) importPriceInput.value = '';
            const priceInput = form.querySelector('input[name="price"]');
            if (priceInput) priceInput.value = '';
            const stockInput = form.querySelector('input[name="stock"]');
            if (stockInput) stockInput.value = '';
            form.querySelector('input[name="name"]').focus();
        } else {
            const modal = document.getElementById('add-product-modal') || form.closest("div[style*=\"fixed\"]");
            if (modal) modal.remove();
            this.loadPage('products');
        }
    }

    handleStockModeChange(checkbox) {
        const form = checkbox.closest('form');
        if (!form) return;

        const qtyCheckbox = form.querySelector('input[name="stockModeQuantity"]');
        const imeiCheckbox = form.querySelector('input[name="stockModeImei"]');

        if (!qtyCheckbox || !imeiCheckbox) return;

        if (checkbox === qtyCheckbox && qtyCheckbox.checked) {
            imeiCheckbox.checked = false;
        } else if (checkbox === imeiCheckbox && imeiCheckbox.checked) {
            qtyCheckbox.checked = false;
        }

        if (!qtyCheckbox.checked && !imeiCheckbox.checked) {
            qtyCheckbox.checked = true;
        }

        const mode = imeiCheckbox.checked ? 'imei' : 'quantity';
        const quantitySection = form.querySelector('[data-stock-mode="quantity"]');
        const imeiSection = form.querySelector('[data-stock-mode="imei"]');
        const stockInput = form.querySelector('input[name="stock"]');
        const imeiField = form.querySelector('[name="imeis"]') || form.querySelector('input[name="imei"]');

        if (quantitySection) quantitySection.style.display = mode === 'quantity' ? 'grid' : 'none';
        if (imeiSection) imeiSection.style.display = mode === 'imei' ? 'block' : 'none';

        if (stockInput) {
            stockInput.disabled = mode === 'imei';
            stockInput.required = mode === 'quantity';
        }
        if (imeiField) {
            imeiField.disabled = mode === 'quantity';
        }
    }

