    // Cập nhật sản phẩm
    updateProduct(event, productId) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);

        // Xử lý IMEI (nếu có)
        const productIndex = this.demoData.products.findIndex(p => p.id === productId);
        if (productIndex === -1) {
            this.showNotification('Không tìm thấy sản phẩm', 'error');
            return;
        }
        const existingProduct = this.demoData.products[productIndex];
        const imeiRaw = (formData.get('imeis') || '').toString().trim();
        const stockModeImei = !!formData.get('stockModeImei');
        const existingImeis = (existingProduct.imeis && Array.isArray(existingProduct.imeis)) ? [...existingProduct.imeis] : (existingProduct.imei ? [existingProduct.imei] : []);
        const imeis = imeiRaw.length > 0 ? [imeiRaw] : existingImeis;
        
        const currentDraft = {
            ...existingProduct,
            id: productId,
            name: formData.get('name'),
            category: formData.get('category'),
        };
        const autoBarcode = this.generateAutoBarcode(currentDraft, productIndex);
        this.demoData.products[productIndex] = {
            ...this.demoData.products[productIndex],
            name: formData.get('name'),
            category: formData.get('category'),
            barcode: this.demoData.products[productIndex].barcode || autoBarcode,
            printBarcode: true,
            importPrice: this.parsePrice(formData.get('importPrice')),
            price: this.parsePrice(formData.get('price')),
            stock: stockModeImei ? imeis.length : parseInt(formData.get('stock') || '0'),
            minStock: stockModeImei ? 0 : (() => { const m = parseInt(formData.get('minStock'), 10); return isNaN(m) ? 1 : Math.max(0, m); })(),
            supplier: formData.get('supplier'),
            hasImei: stockModeImei,
            imeis: imeis
        };
        
        this.saveToLocalStorage();
        this.showNotification(`Đã cập nhật sản phẩm ${formData.get('name')}`, 'success');
        this.loadPage('products');
        const modal = form.closest("div[style*=\"fixed\"]"); if(modal) modal.remove();
    }

    calcEan13CheckDigit(data12) {
        const digits = String(data12 || '').replace(/\D/g, '').slice(0, 12).padStart(12, '0');
        let sum = 0;
        for (let i = 0; i < 12; i++) {
            const n = parseInt(digits[i], 10) || 0;
            sum += (i % 2 === 0) ? n : n * 3;
        }
        return (10 - (sum % 10)) % 10;
    }

    generateAutoBarcode(product, indexHint) {
        const random9 = String(Math.floor(Math.random() * 1000000000)).padStart(9, '0');
        const body12 = ('893' + random9).slice(0, 12);
        return body12 + String(this.calcEan13CheckDigit(body12));
    }

    _isCategoryRoot(c) { return c.parent === null || c.parent === undefined || c.parent === ''; }
    _getCategoryById(id) { return (this.demoData.categories || []).find(c => c.id === id); }

    getCategoryOptionsWithSelected(selectedCategory) {
        const categories = (this.demoData.categories || []).length ? this.demoData.categories : [];
        const selected = (selectedCategory || '').trim();
        let options = '<option value="">Chọn danh mục</option>';
        const allNames = categories.map(c => (c.name || '').trim()).filter(Boolean);
        const nameCount = {};
        allNames.forEach(n => { nameCount[n] = (nameCount[n] || 0) + 1; });
        const rootNames = new Set(categories.filter(c => this._isCategoryRoot(c)).map(c => c.name));
        const allCategoryNames = new Set(categories.map(c => c.name));
        categories.forEach(c => categories.filter(s => s.parent === c.id).forEach(s => allCategoryNames.add(s.name)));
        const hasInList = selected && allCategoryNames.has(selected);
        if (selected && !hasInList) {
            options += `<option value="${selected.replace(/"/g, '&quot;')}" selected>${selected.replace(/</g, '&lt;')}</option>`;
        }
        const parentOccurrence = {};
        categories.forEach(category => {
            const isRoot = this._isCategoryRoot(category);
            const isOrphan = !isRoot && !this._getCategoryById(category.parent);
            if (!isRoot && !isOrphan) return;
            const pName = category.name || '';
            parentOccurrence[pName] = (parentOccurrence[pName] || 0) + 1;
            const pCount = nameCount[pName] || 0;
            const parentLabel = pCount > 1 && parentOccurrence[pName] > 1 ? `${pName} (${parentOccurrence[pName]})` : pName;
            const sel = category.name === selected ? 'selected' : '';
            options += `<option value="${pName.replace(/"/g, '&quot;')}" ${sel}>${parentLabel.replace(/</g, '&lt;')}</option>`;
            const subCategories = categories.filter(c => c.parent === category.id);
            subCategories.forEach(subCat => {
                const fullVal = `${category.name} > ${subCat.name}`;
                const label = (nameCount[subCat.name] || 0) > 1 ? `${category.name} › ${subCat.name}` : `-- ${subCat.name}`;
                const childMatchesOnly = subCat.name === selected && !rootNames.has(selected);
                const subSel = (fullVal === selected || childMatchesOnly) ? 'selected' : '';
                options += `<option value="${fullVal.replace(/"/g, '&quot;')}" ${subSel}>${label.replace(/</g, '&lt;')}</option>`;
            });
        });
        return options;
    }
    
