    addCategory(event) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);
        const categoryName = (formData.get('categoryName') || '').trim();
        if (!categoryName) {
            this.showNotification('Vui lòng nhập tên danh mục.', 'warning');
            return;
        }
        const categories = (this.demoData.categories || []).length ? this.demoData.categories : [];
        const exists = categories.some(c => (c.parent == null || c.parent === '') && (c.name || '').trim().toLowerCase() === categoryName.toLowerCase());
        if (exists) {
            this.showNotification(`Danh mục gốc "${categoryName}" đã tồn tại. Vui lòng dùng tên khác.`, 'warning');
            return;
        }
        const newCategory = {
            id: 'cat' + Date.now(),
            name: categoryName,
            parent: null,
            level: 0
        };
        
        categories.push(newCategory);
        this.demoData.categories = categories;
        this.saveToLocalStorage();
        this.showNotification(`Đã thêm danh mục "${categoryName}"`, 'success');
        this.loadPage('categories');
        const modal = form.closest("div[style*=\"fixed\"]"); if(modal) modal.remove();
    }

    addSubCategory(event) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);
        const categoryName = (formData.get('categoryName') || '').trim();
        const parentId = formData.get('parentCategory');
        if (!categoryName) {
            this.showNotification('Vui lòng nhập tên danh mục con.', 'warning');
            return;
        }
        const categories = (this.demoData.categories || []).length ? this.demoData.categories : [];
        const exists = categories.some(c => String(c.parent || '') === String(parentId || '') && (c.name || '').trim().toLowerCase() === categoryName.toLowerCase());
        if (exists) {
            this.showNotification(`Danh mục con "${categoryName}" đã tồn tại trong nhóm này. Vui lòng dùng tên khác.`, 'warning');
            return;
        }
        const newCategory = {
            id: 'cat' + Date.now(),
            name: categoryName,
            parent: parentId,
            level: 1
        };
        
        categories.push(newCategory);
        this.demoData.categories = categories;
        this.saveToLocalStorage();
        this.showNotification(`Đã thêm danh mục con "${categoryName}"`, 'success');
        this.loadPage('categories');
        const modal = form.closest("div[style*=\"fixed\"]"); if(modal) modal.remove();
    }

