    toggleCustomerFields(customerType) {
        const companyField = document.getElementById('company-field');
        const taxField = document.getElementById('tax-field');
        const companyInput = document.querySelector('input[name="companyName"]');
        const departmentInput = document.querySelector('input[name="department"]');
        
        if (customerType === 'doanh-nghiep') {
            companyField.style.display = 'block';
            taxField.style.display = 'block';
            companyInput.required = true;
        } else {
            companyField.style.display = 'none';
            taxField.style.display = 'none';
            companyInput.required = false;
            companyInput.value = '';
            if (departmentInput) departmentInput.value = '';
            document.querySelector('input[name="taxCode"]').value = '';
        }
    }

    quickAddCustomer(event) {
        event.preventDefault();
        const formData = new FormData(event.target);
        
        const maxNum = Math.max(0, ...(this.demoData.customers || []).map(c => {
            const m = (c.id || '').match(/^KH(\d+)$/);
            return m ? parseInt(m[1], 10) : 0;
        }));
        const newCustomer = {
            id: 'KH' + String(maxNum + 1).padStart(3, '0'),
            name: formData.get('customerName'),
            type: formData.get('customerType') || 'ca-nhan',
            companyName: formData.get('companyName') || '',
            department: formData.get('department') || '',
            phone: formData.get('customerPhone') || '',
            email: formData.get('customerEmail') || '',
            address: formData.get('customerAddress') || '',
            taxCode: formData.get('taxCode') || '',
            notes: formData.get('customerNotes') || '',
            debt: 0,
            totalOrders: 0
        };

        // Add to demo data
        this.demoData.customers.push(newCustomer);
        this.saveToFirebaseImmediate().then(ok => { if (!ok) this.saveToLocalStorage(); });

        // Update customer select in the current form (Create Order)
        const customerSelect = document.getElementById('customer-select');
        if (customerSelect) {
            const newOption = document.createElement('option');
            newOption.value = newCustomer.id;
            newOption.textContent = `${newCustomer.name}${newCustomer.phone ? ' - ' + newCustomer.phone : ''}`;
            customerSelect.appendChild(newOption);
            customerSelect.value = newCustomer.id;
        }

        if (this.currentPage === 'sales' || (typeof document !== 'undefined' && document.getElementById('orders-mobile-edit-root')?.classList.contains('orders-mobile-edit-root--pos'))) {
            this.selectPOSCustomer(newCustomer.id, newCustomer.name);
            const inp = document.getElementById('pos-customer-search');
            const nameEl = document.getElementById('pos-customer-name');
            if (inp) inp.value = newCustomer.name;
            if (nameEl) nameEl.textContent = newCustomer.name;
            this.filterPOSCustomer(newCustomer.name || '');
        }

        // Close the modal
        const modal = event.target.closest("div[style*=\"fixed\"]");
        if (modal) modal.remove();
        
        // Clear search box (nếu có - trang Create Order)
        const searchInput = document.getElementById('customer-search');
        if (searchInput) {
            searchInput.value = '';
            this.filterCustomers(''); // Reset filter
        }

        this.showNotification(`Đã thêm khách hàng "${newCustomer.name}" và chọn tự động`, 'success');
    }

